// Fetches the CSES problem list and writes docs/cses-categories.js
// with both a category map and a display-name map for the browser to use.
const fs = require('fs');

(async () => {
  try {
    const res = await fetch('https://cses.fi/problemset/', {
      headers: { 'User-Agent': 'Mozilla/5.0 (compatible; readme-bot)' },
      signal: AbortSignal.timeout(20000),
    });
    if (!res.ok) { console.error('CSES fetch failed:', res.status); process.exit(0); }

    const html = await res.text();
    const norm = (s) => s.toLowerCase().replace(/[^a-z0-9]/g, '');
    const tokens = [];
    const h2Re = /<h2>([^<]+)<\/h2>/g;
    const taskRe = /class="task"><a href="[^"]*\/task\/\d+"[^>]*>([^<]+)<\/a>/g;
    let m;
    while ((m = h2Re.exec(html))) tokens.push({ pos: m.index, type: 'cat', name: m[1].trim() });
    while ((m = taskRe.exec(html))) tokens.push({ pos: m.index, type: 'task', name: m[1].trim() });
    tokens.sort((a, b) => a.pos - b.pos);

    let cur = 'Other';
    const cats = {};   // norm(name) -> category
    const names = {};  // norm(name) -> display name
    for (const t of tokens) {
      if (t.type === 'cat') cur = t.name;
      else {
        const key = norm(t.name);
        cats[key] = cur;
        names[key] = t.name;  // preserve original display name
      }
    }

    fs.writeFileSync(
      'docs/cses-categories.js',
      '// Auto-generated by update-cses-categories.js — do not edit manually\n' +
      'window.CSES_CATEGORIES = ' + JSON.stringify(cats, null, 2) + ';\n' +
      'window.CSES_NAMES = ' + JSON.stringify(names, null, 2) + ';\n'
    );
    console.log(`Generated docs/cses-categories.js: ${Object.keys(cats).length} problems across ${new Set(Object.values(cats)).size} categories`);
  } catch (e) {
    console.error('Error generating CSES categories:', e.message);
    process.exit(0); // non-fatal — existing file stays
  }
})();
